    "text": "等。\n\n决\n策\n逻\n辑\n只\n要\n把\n它\n们\n串\n起\n来\n：\n\nfunction Phi_scorer(answer, query, user_state): L = logic_score(answer) # 逻 辑 严 谨 度 C = connectivity_score(answer) # 关 联 广 度 E = evidence_score(answer) # 证 据 充 分 度 V = verifiability_score(answer) # 可 验 证 性 R = robustness_score(answer) # 稳 健 性 H = humanity_score(answer, user_state) # 人 性 / 共 情 U = usability_score(answer) # 好 用 度 /IUI S = safety_score(answer) # 安 全 度 N = novelty_score(answer) # 新 意 T = completeness_score(answer) # 完 成 度 / 闭 环\n return {L,C,E,V,R,H,U,S,N,T}\n增\n强\n指\n标\n作\n为\n二\n级\n特\n征\n输\n入\n\nT\nσ\n、\nScore_aggregator\n：\n\nfunction Advanced_metrics(answer, query): LCR = logic_consistency_rate(answer) Π D = pi_depth_index(answer) XVR = cross_verification_rate(answer) EXI = executability_index(answer) EDI = ease_of_doing_index(answer) ψ ⁺ = positive_valence(answer, query) ... return {LCR, Π D, XVR, EXI, EDI, ψ ⁺ , ...}\n4.5 T σ & B σ ： 可 信 刻 度 + 黑 子 刻 度\nT\nσ\n\n在\n白\n皮\n书\n和\n增\n强\n指\n标\n里\n已\n经\n有\n定\n义\n：\n\n是\n“\n逻\n辑\n+\n证\n据\n+\n光\n性\n”\n等\n多\n维\n的\n综\n合\n可\n信\n度\n估\n计。\n\n我\n们\n可\n以\n这\n样\n写\n：\n\nfunction Trust_estimator(phi_vec, metrics): # 逻 辑 相 关 LCR = metrics.LCR p_logic = min(LCR, phi_vec.L) # 证 据 ..."
